const EXPECTED_KEY = 'YOUR_N8N_API_KEY';
const incoming = $input.first();
const headers = incoming.json.headers || {};
const receivedKey = headers['x-ddvb-api-key'] || headers['X-DDVB-API-Key'] || '';
if (receivedKey.trim() !== EXPECTED_KEY.trim()) {
  throw new Error('Unauthorized: invalid or missing X-DDVB-API-Key');
}
const body = incoming.json.body || incoming.json;
return [{ json: body }];

const item = $input.first();
const body = item.json.body || item.json;
const jobId = body.jobId || 'job-' + Date.now();
const callbackUrl = (body.callbackUrl || '').replace(/\r?\n/g, '').trim();
return [{ json: { ...body, jobId, callbackUrl, timestamp: new Date().toISOString() } }];

const inputData = $input.first().json;

function normalize(v) {
  return String(v ?? '').trim();
}

const mode = normalize(inputData.mode);
const articleType = normalize(inputData.articleType);
const speakerId = normalize(inputData.speakerId);
const topic = normalize(inputData.topic);
const description = normalize(inputData.description);
const theses = inputData.theses;
const jobId = normalize(inputData.jobId);
const callbackUrl = normalize(inputData.callbackUrl);

const missingFields = [];
if (!mode) missingFields.push('mode (scratch/theses)');
if (!articleType) missingFields.push('articleType (thought_leadership/howto/pr_news)');
if (!speakerId) missingFields.push('speakerId');
if (mode === 'scratch' && !topic) missingFields.push('topic');
if (mode === 'scratch' && !description) missingFields.push('description');
if (mode === 'theses' && (!theses || !Array.isArray(theses) || theses.length === 0)) missingFields.push('theses (array of strings)');
if (!jobId) missingFields.push('jobId');

const validArticleTypes = ['thought_leadership', 'howto', 'pr_news'];
if (articleType && !validArticleTypes.includes(articleType)) {
  missingFields.push('articleType must be one of: thought_leadership, howto, pr_news');
}

const validModes = ['scratch', 'theses'];
if (mode && !validModes.includes(mode)) {
  missingFields.push('mode must be one of: scratch, theses');
}

return [{
  json: {
    ...inputData,
    mode,
    articleType,
    speakerId,
    topic,
    description,
    theses: mode === 'theses' ? theses : [],
    jobId,
    callbackUrl,
    isValid: missingFields.length === 0,
    missingFields,
  },
}];

const input = $input.first().json;
const original = $("Parse Request").first().json;

let profile = null;
try {
  const rawContent = input.content || '';
  if (rawContent) {
    const decoded = Buffer.from(rawContent.replace(/\n/g, ''), 'base64').toString('utf-8');
    profile = JSON.parse(decoded);
  }
} catch(e) { profile = null; }

const fallbackProfiles = {
  maria_arkhangelskaya: {
    name_ru: 'Мария Архангельская',
    title_ru: 'Генеральный директор и управляющий партнёр',
    company: 'DDVB',
    voice_guidelines: 'Экспертный, но не менторский. Конкретные примеры. Живые глаголы.',
  },
  default: {
    name_ru: 'Эксперт DDVB',
    title_ru: 'Специалист',
    company: 'DDVB',
    voice_guidelines: 'Экспертный тон. Конкретика. Живой язык.',
  },
};

if (!profile) {
  const speakerId = original.speakerId || '';
  profile = fallbackProfiles[speakerId] || fallbackProfiles.default;
}

return [{
  json: {
    ...original,
    profile,
    speakerName: profile.name_ru || profile.name || original.speakerId,
    speakerTitle: profile.title_ru || profile.title || '',
    speakerCompany: profile.company || 'DDVB',
    speakerVoiceGuidelines: profile.voice_guidelines || profile.tone || '',
  }
}];

const d = $input.first().json;
const topic = d.topic || '';
const description = d.description || '';
const articleType = d.articleType || '';
const ruContext = 'Россия, российский рынок: ';

const queries = [
  ruContext + topic + ' — отраслевые тренды, состояние рынка, ключевые игроки',
  ruContext + topic + ' — экспертные мнения, аналитика, прогнозы',
  ruContext + topic + ' — практические примеры, кейсы, успешные проекты',
  ruContext + topic + ' — статистика, метрики, исследования',
];

return queries.map((q, i) => ({
  json: {
    ...d,
    query: q,
    streamId: i + 1,
    topic,
    description,
    articleType,
  }
}));

const items = $input.all();
let mergedContent = '';
let allSources = [];

for (const item of items) {
  const json = item.json;
  const content = json.choices?.[0]?.message?.content || '';
  mergedContent += '\n## Поток ' + json.streamId + ': ' + json.query + '\n';
  mergedContent += content;
  if (json.sources) {
    allSources = allSources.concat(json.sources);
  }
}

// Back-reference Parse Profile to preserve original request data
const first = $("Parse Profile").first().json;

return [{
  json: {
    ...first,
    researchContent: mergedContent,
    researchSources: allSources,
    researchMode: 'scratch',
    streamCount: items.length,
  }
}];

const d = $input.first().json;
const theses = d.theses || [];
const topic = d.topic || d.description || '';
const ruContext = 'Россия, российский рынок: ';

return theses.map((thesis, i) => ({
  json: {
    ...d,
    thesis,
    thesisIndex: i + 1,
    totalTheses: theses.length,
    topic,
    query: ruContext + topic + ' — ' + thesis,
  }
}));

